mod history; pub struct Buffer { pub lines: Vec<String>, pub path: Option<String>, pub history: history::History, } impl Buffer { pub fn new() -> Self { Self { lines: vec![String::new()], path: None, history: history::History::new() } } pub fn insert_line(&mut self, row: usize, col: usize, text: &str) { if row < self.lines.len() { self.lines[row].insert_str(col, text); self.history.undo_stack.push(history::Command::Insert { row, col, text: text.to_string() }); } } pub fn get_text(&self) -> String { self.lines.join("\n") } }
